import{_ as s,o as t,c as a,ae as n}from"./chunks/framework.BGHOrOyn.js";const k=JSON.parse('{"title":"How to use the LXD Proxy Device to map ports between the host and the containers","description":"","frontmatter":{},"headers":[],"relativePath":"software-engineering/containerisation/lxc-lxd/how-to-use-the-lxd-proxy-device-to-map-ports-between-the-host-and-the-containers.md","filePath":"software-engineering/containerisation/lxc-lxd/how-to-use-the-lxd-proxy-device-to-map-ports-between-the-host-and-the-containers.md"}'),i={name:"software-engineering/containerisation/lxc-lxd/how-to-use-the-lxd-proxy-device-to-map-ports-between-the-host-and-the-containers.md"};function o(h,e,r,p,l,c){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="how-to-use-the-lxd-proxy-device-to-map-ports-between-the-host-and-the-containers" tabindex="-1">How to use the LXD Proxy Device to map ports between the host and the containers <a class="header-anchor" href="#how-to-use-the-lxd-proxy-device-to-map-ports-between-the-host-and-the-containers" aria-label="Permalink to &quot;How to use the LXD Proxy Device to map ports between the host and the containers&quot;">​</a></h1><p>LXD supports <a href="https://github.com/lxc/lxd/blob/master/doc/containers.md#type-proxy" target="_blank" rel="noreferrer"><em><strong>proxy devices</strong></em></a>, which is a way to proxy connections between the host and containers. This includes <em>TCP, UDP and Unix socket connections</em>. For example, when someone connects to your host on port 80 (http), then this connection can be proxied to a container using a <em>proxy device</em>. In that way, you can isolate your Web server into a LXD container. By using a TCP proxy device, you do not need to use <code>iptables</code> instead.</p><p>Earlier I wrote that you can make a connection in any direction. For example, you can<a href="https://blog.simos.info/how-to-easily-run-graphics-accelerated-gui-apps-in-lxd-containers-on-your-ubuntu-desktop/" target="_blank" rel="noreferrer"> expose the host’s Unix socket for X11 into the container so that the container can run X11 applications and have them appear on the host’s X11 server</a>. Or, in the other way round, you can <a href="https://blog.simos.info/how-to-manage-lxd-from-within-one-of-its-containers/" target="_blank" rel="noreferrer">make available LXD’s Unix socket at the host to a container so that you can manage LXD from inside a container</a>.</p><p>Note that LXD 3.0.x only supports <em><strong>TCP to TCP</strong></em> proxy devices. Support for UDP and Unix sockets was added in later versions.</p><h2 id="launching-a-container-and-setting-up-a-web-server" tabindex="-1">Launching a container and setting up a Web server <a class="header-anchor" href="#launching-a-container-and-setting-up-a-web-server" aria-label="Permalink to &quot;Launching a container and setting up a Web server&quot;">​</a></h2><p>Let’s launch a container, install a Web server, and, then expose the Web server to the local network (or the Internet, if you are using a VPS/Internet server).</p><p>First, launch the container.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">lxc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> launch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> ubuntu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">18.04</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> mycontainer</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Creating</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> mycontainer</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Starting</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> mycontainer</span></span></code></pre></div><p>We get a shell into the container, update the package list and install <code>nginx</code>. Finally, verify that <code>nginx</code> is running.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ubuntu@mycontainer:~$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ubuntu@mycontainer:~$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ubuntu@mycontainer:~$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">...</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Welcome</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nginx!</span></span></code></pre></div><h3 id="exposing-the-web-server-of-a-container-to-the-internet" tabindex="-1">Exposing the Web server of a container to the Internet <a class="header-anchor" href="#exposing-the-web-server-of-a-container-to-the-internet" aria-label="Permalink to &quot;Exposing the Web server of a container to the Internet&quot;">​</a></h3><p>We logout to the host and verify that there is no Web server already running on port 80. If port 80 is not available on your host, change it to something else, like 8000. Finally, we create <em><strong>the TCP to TCP LXD Proxy Device</strong></em>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ubuntu@mycontainer:~$ logout</span></span>
<span class="line"><span>$ lxc config device add mycontainer myport80 proxy listen=tcp:0.0.0.0:80 connect=tcp:127.0.0.1:80</span></span>
<span class="line"><span>Device myport80 added to mycontainer</span></span></code></pre></div><p>The command that creates the proxy device is made of the following components.</p><ol><li><code>lxc config device add</code>, we _<strong>config</strong>_ure to have a <em><strong>device</strong></em> _<strong>add</strong>_ed,</li><li><code>mycontainer</code>, to the container <em><strong>mycontainer</strong></em>,</li><li><code>myport80</code>, with name <em><strong>myport80</strong></em>,</li><li><code>proxy</code>, a <em><strong>proxy</strong></em> device, we are adding a LXD Proxy Device.</li><li><code>listen=tcp:0.0.0.0:80</code>, we <em><strong>listen</strong></em> (on the host by default) on all network interfaces on TCP port 80.</li><li><code>connect=tcp:127.0.0.1:80</code>, we connect (to the container by default) to the existing TCP port 80 on localhost, which is our <code>nginx</code>.</li></ol><p>Note that previously you would specify hostnames when you were creating LXD Proxy Devices. This is no longer supported (has security implications), therefore you get an error if you specify a hostname such as <code>localhost</code>. This post was primarily written because the top Google result on proxy devices is an old Reddit read-only post that suggests to use <code>localhost</code>.</p><p>Let’s test that the Web server in the container is accessible on the host. We can use both <code>localhost</code> (or <code>127.0.0.1</code>) on the host to access the website of the container. We can also use the public IP address of the host (in this case, the LAN IP address) to access the container.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> http</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//localhost</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Welcome</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> to</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> nginx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> http</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//192.168.1.100</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Welcome</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> to</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> nginx</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span></span></code></pre></div><h3 id="other-features-of-the-proxy-devices" tabindex="-1">Other features of the proxy devices <a class="header-anchor" href="#other-features-of-the-proxy-devices" aria-label="Permalink to &quot;Other features of the proxy devices&quot;">​</a></h3><p>By default, a proxy device exposes an existing service in the container to the host. If we need to expose an existing service on the host to a container, we would add the parameter <code>bind=container</code> to the proxy device command.</p><p>You can expose a single webserver to a port on the host. But how do you expose many web servers in containers to the host? You can use a reverse proxy that goes in front of the containers. To retain the remote IP address of the clients visiting the Web servers, you can add the <code>proxy_protocol=true</code> to enable support for the PROXY protocol. Note that you also need to enable the PROXY protocol on the reverse proxy.</p><p><img src="https://secure.gravatar.com/avatar/5c04c6b5f513d926ea9d77782a3843a1?s=100&amp;d=wavatar&amp;r=g" alt="Simos Xenitellis"></p>`,22)])])}const g=s(i,[["render",o]]);export{k as __pageData,g as default};
